#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Qu{
    int x,xs,id;
};


int n,q,r,t[N],cnt,dis[N],ans[N];
int dep[N],f[N][18],b[N],c[N];
vector<int> g[N];
vector<Qu> qu[N];

void dfs1(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int y:g[x]){
        f[y][0]=x;
        for(int i=1;f[f[y][i-1]][i-1];i++)
            f[y][i]=f[f[y][i-1]][i-1];
        dfs1(y,x);
    }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=17;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=17;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

void add(int x,int k){
    for(;x<=q;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void dfs2(int x){
    if(b[x]<=q)
        add(b[x],1);
    for(Qu i:qu[x])
        ans[i.id]+=i.xs*ask(i.x-1);
    for(int y:g[x])
        dfs2(y);
    if(b[x]<=q)
        add(b[x],-1);
}

int main(){
    memset(b,0x3f,sizeof(b));
    scanf("%d",&n);
    for(int i=1,f;i<=n;i++){
        scanf("%d",&f);
        if(!f)
            r=i;
        else
            g[f].push_back(i);
    }
    dfs1(r,0);
    scanf("%d",&q);
    for(int i=1;i<=q;i++){
        int op,x,y,c;
        scanf("%d%d",&op,&x);
        if(op==1){
            scanf("%d%d",&y,&c);
            int lca=LCA(x,y);
            cnt++;
            dis[cnt]=dep[x]+dep[y]-2*dep[lca]+1;
            if(i-c>1){
                qu[x].push_back({i-c,1,cnt});
                qu[y].push_back({i-c,1,cnt});
                qu[lca].push_back({i-c,-1,cnt});
                if(f[lca][0])
                    qu[f[lca][0]].push_back({i-c,-1,cnt});
            }
        }else
            b[x]=min(b[x],i);
    }
    dfs2(r);
    for(int i=1;i<=cnt;i++)
        printf("%d %d\n",dis[i],ans[i]);
    return 0;
}
